import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { showToast } from '../../utils/toast'
import { useAuth } from '../../context/AuthContext'
import { taskService, productService } from '../../services/api'
import '../../styles/technician/technician-tasks.css'

const STATUS_OPTIONS = [
  { value: 'ALL', label: 'Tất cả trạng thái công việc' },
  { value: 'PENDING', label: 'Chờ xử lý' },
  { value: 'IN_PROGRESS', label: 'Đang thực hiện' },
  { value: 'COMPLETED', label: 'Hoàn thành' },
  { value: 'CANCELLED', label: 'Đã hủy' },
  { value: 'OVERDUE', label: 'Quá hạn' },
]

const TASK_TYPE_OPTIONS = [
  { value: 'POND_PROCESS', label: 'Xử lý ao (POND_PROCESS)' },
  { value: 'FEEDING', label: 'Cho ăn (FEEDING)' },
  { value: 'TREATMENT', label: 'Cho thuốc (TREATMENT)' },
  { value: 'ENVIRONMENTAL_CHECK', label: 'Kiểm tra môi trường (ENVIRONMENTAL_CHECK)' },
  { value: 'HARVEST', label: 'Thu hoạch (HARVEST)' },
  { value: 'OTHER', label: 'Công việc khác (OTHER)' },
]

const normalize = (v) => String(v || '').trim().toUpperCase()
const formatDate = (v) => (v ? new Date(v).toLocaleString('vi-VN') : '-')

const getStatusLabel = (status) => {
  switch (normalize(status)) {
    case 'PENDING': return 'Chờ xử lý'
    case 'IN_PROGRESS': return 'Đang thực hiện'
    case 'COMPLETED': return 'Hoàn thành'
    case 'CANCELLED': return 'Đã hủy'
    case 'OVERDUE': return 'Quá hạn'
    default: return status || '-'
  }
}

const getStatusClass = (status) => {
  switch (normalize(status)) {
    case 'PENDING': return 'table-status-badge table-status-inactive'
    case 'IN_PROGRESS': return 'table-status-badge table-status-active'
    case 'COMPLETED': return 'table-status-badge table-status-completed'
    case 'CANCELLED': return 'table-status-badge bg-gray-400 text-white'
    case 'OVERDUE': return 'table-status-badge bg-red-500 text-white'
    default: return 'table-status-badge'
  }
}

const TechnicianTasks = () => {
  const { user } = useAuth()

  // ===== DATA STATE =====
  const [tasks, setTasks] = useState([])
  const [ponds, setPonds] = useState([])
  const [products, setProducts] = useState([])
  const [workers, setWorkers] = useState([])

  // ===== UI STATE =====
  const [loading, setLoading] = useState(true)
  const [loadingPonds, setLoadingPonds] = useState(false)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('ALL')
  const [currentPage, setCurrentPage] = useState(1)
  const [pageSize, setPageSize] = useState(10)
  const [selectedTask, setSelectedTask] = useState(null)
  const [isCreateOpen, setIsCreateOpen] = useState(false)

  // ===== FORM STATE =====
  const initialForm = {
    task_type: '',
    pond_id: '',
    season_id: '',
    task_title: '',
    description: '',
    start_date: '',
    due_date: '',
    assigned_workers: [],
    product_id: '',
    quantity: '',
  }
  const [form, setForm] = useState(initialForm)

  // =========================
  // FETCH DATA
  // =========================
  const fetchTasks = useCallback(async () => {
    try {
      const res = await taskService.getAllTasks()
      setTasks(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được danh sách công việc', type: 'error' })
    }
  }, [])

  const fetchProducts = useCallback(async () => {
    try {
      const res = await productService.getProducts()
      setProducts(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được danh mục sản phẩm', type: 'error' })
    }
  }, [])

  const fetchWorkersStatus = useCallback(async () => {
    try {
      const res = await taskService.getWorkersStatus()
      setWorkers(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải được trạng thái nhân công', type: 'error' })
    }
  }, [])

  useEffect(() => {
    const loadInitialData = async () => {
      setLoading(true)
      await Promise.all([
        fetchTasks(),
        fetchProducts(),
        fetchWorkersStatus()
      ])
      setLoading(false)
    }
    loadInitialData()
  }, [fetchTasks, fetchProducts, fetchWorkersStatus])

  // NGHIEP VU CHỌN LOẠI VIỆC -> GỌI API LỌC AO ĐỘNG THÔNG MINH
  const handleTypeChange = async (e) => {
    // Đảm bảo mã loại công việc luôn luôn viết hoa, không bị thừa khoảng trắng
    const typeCode = e.target.value ? e.target.value.trim().toUpperCase() : ''

    setForm(prev => ({
      ...prev,
      task_type: typeCode,
      pond_id: '',
      season_id: '',
      product_id: '',
      quantity: ''
    }))
    setPonds([])

    if (!typeCode) return

    setLoadingPonds(true)
    try {
      // Truyền giá trị đã được chuẩn hóa ra API
      const res = await taskService.getPondsByType(typeCode)
      setPonds(res?.data?.data || [])
    } catch (err) {
      console.error("API Error Details:", err.response?.data) // In ra để debug nếu có lỗi 400/500
      showToast({ title: 'Lỗi khi tự động lọc danh sách ao tương ứng', type: 'error' })
    } finally {
      setLoadingPonds(false)
    }
  }

  // TỰ ĐỘNG ĐÍNH KÈM SEASON_ID KHI CHỌN AO NUÔI
  const handlePondChange = (e) => {
    const pondId = e.target.value
    const selectedPondObj = ponds.find(p => String(p.pond_id) === String(pondId))

    setForm(prev => ({
      ...prev,
      pond_id: pondId,
      season_id: selectedPondObj ? selectedPondObj.season_id : ''
    }))
  }

  // =========================
  // FILTER LOGIC (MAIN TABLE)
  // =========================
  const filteredTasks = useMemo(() => {
    const s = search.trim().toLowerCase()
    return tasks.filter((t) => {
      const matchSearch = !s ||
        String(t.task_title || '').toLowerCase().includes(s) ||
        String(t.pond_name || '').toLowerCase().includes(s)

      const matchStatus = statusFilter === 'ALL' || normalize(t.status) === statusFilter
      return matchSearch && matchStatus
    })
  }, [tasks, search, statusFilter])

  const totalPages = Math.max(1, Math.ceil(filteredTasks.length / pageSize))
  useEffect(() => {
    if (currentPage > totalPages) {
      setCurrentPage(totalPages)
    }
  }, [filteredTasks.length, pageSize, totalPages, currentPage])

  const safePage = Math.min(currentPage, totalPages)
  const startIndex = (safePage - 1) * pageSize
  const endIndex = Math.min(startIndex + pageSize, filteredTasks.length)
  const paginatedTasks = filteredTasks.slice(startIndex, endIndex)

  const isProductRequired = useMemo(() => {
    return ['FEEDING', 'TREATMENT', 'POND_PROCESS'].includes(form.task_type)
  }, [form.task_type])

  // =========================
  // ACTION HANDLERS
  // =========================
  const toggleWorker = (id, isBusy) => {
    if (isBusy) {
      alert("Công nhân này hiện đang thực hiện một công việc khác. Hãy chọn người sẵn sàng!")
      return
    }
    setForm((prev) => {
      const list = prev.assigned_workers || []
      const exists = list.includes(id)
      return {
        ...prev,
        assigned_workers: exists ? list.filter((x) => x !== id) : [...list, id],
      }
    })
  }

  const handleCreateTask = async () => {
    if (!form.description?.trim()) {
      showToast({ title: 'Vui lòng nhập hướng dẫn chi tiết công việc', type: 'warning' })
      return
    }
    if (!form.assigned_workers || form.assigned_workers.length === 0) {
      showToast({ title: 'Vui lòng chọn ít nhất một nhân công gán việc', type: 'warning' })
      return
    }

    const confirmAction = window.confirm("Xác nhận phân công công việc này xuống hạ tầng ao nuôi?")
    if (!confirmAction) return

    try {
      const submitData = { ...form }

      // Tự sinh tiêu đề nhanh gọn nếu người dùng bỏ trống dựa theo Loại công việc
      if (!submitData.task_title?.trim()) {
        const typeOpt = TASK_TYPE_OPTIONS.find(o => o.value === form.task_type)
        submitData.task_title = typeOpt ? `Công tác ${typeOpt.label}` : 'Công việc kỹ thuật ao'
      }

      if (!isProductRequired) {
        delete submitData.product_id
        delete submitData.quantity
      } else {
        submitData.quantity = parseFloat(submitData.quantity) || 0
      }

      // Bản đồ hóa sang API Create mới tinh
      await taskService.createTask(submitData)
      showToast({ title: 'Phân công công việc mới thành công', type: 'success' })
      setForm(initialForm)
      setIsCreateOpen(false)

      // Reload lại data
      await Promise.all([fetchTasks(), fetchWorkersStatus()])
    } catch (err) {
      const errMsg = err.response?.data?.message || 'Tạo công việc thất bại'
      showToast({ title: errMsg, type: 'error' })
    }
  }

  const handleStatusChange = async (taskId, newStatus) => {
    try {
      if (normalize(newStatus) === 'COMPLETED') {
        const confirmComplete = window.confirm("Đánh dấu HOÀN THÀNH? Hệ thống sẽ tự động xuất kho vật tư hạch toán chi phí.")
        if (!confirmComplete) return
        await taskService.completeTask(taskId)
      } else {
        await taskService.updateTaskStatus(taskId, newStatus)
      }
      showToast({ title: 'Cập nhật trạng thái công việc thành công', type: 'success' })
      setSelectedTask(null)
      await Promise.all([fetchTasks(), fetchWorkersStatus()])
    } catch (err) {
      showToast({ title: err.response?.data?.message || 'Lỗi cập nhật trạng thái', type: 'error' })
    }
  }

  const handleCancelTask = async (taskId) => {
    const confirmCancel = window.confirm("Bạn có chắc chắn muốn HỦY bỏ hoàn toàn công việc này không?")
    if (!confirmCancel) return

    try {
      await taskService.cancelTask(taskId)
      showToast({ title: 'Đã hủy công việc thành công', type: 'success' })
      setSelectedTask(null)
      await Promise.all([fetchTasks(), fetchWorkersStatus()])
    } catch (err) {
      showToast({ title: err.response?.data?.message || 'Không thể hủy công việc', type: 'error' })
    }
  }

  if (loading) {
    return (
      <div className="dashboard admin-page">
        <div className="flex-center table-loading-container">
          <div className="spinner" />
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard admin-page technician-tasks">
      <div className="table-container table-panel">

        {/* HEADER */}
        <div className="table-header">
          <div>
            <h2>Quản lý công việc</h2>
            <p className="table-subtitle">Phân công và giám sát tiến độ công việc kỹ thuật ao nuôi thông minh</p>
          </div>
          <button type="button" className="btn btn-primary" onClick={() => setIsCreateOpen(true)}>
            + Phân công công việc mới
          </button>
        </div>

        {/* TOOLBAR & FILTER */}
        <div className="table-toolbar">
          <div className="table-search">
            <span className="table-search-icon">⌕</span>
            <input
              type="text"
              placeholder="Tìm theo tên công việc hoặc ao..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
            />
          </div>

          <select
            className="table-filter"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            {STATUS_OPTIONS.map((o) => (
              <option key={o.value} value={o.value}>{o.label}</option>
            ))}
          </select>
        </div>

        {/* DATA TABLE */}
        <div className="table-wrapper">
          <table className="table-base">
            <thead>
              <tr>
                <th>Công việc</th>
                <th>Ao nuôi</th>
                <th>Người phụ trách</th>
                <th>Hạn hoàn thành</th>
                <th>Trạng thái</th>
                <th>Hành động</th>
              </tr>
            </thead>
            <tbody>
              {paginatedTasks.length === 0 ? (
                <tr>
                  <td className="table-empty-row" colSpan="6">
                    Không có dữ liệu công việc phù hợp bộ lọc hiện tại.
                  </td>
                </tr>
              ) : (
                paginatedTasks.map((t) => (
                  <tr key={t.task_id}>
                    <td>
                      <div className="technician-ponds_name-block">
                        <strong>{t.task_title}</strong>
                        <span style={{ fontSize: '0.85rem', color: '#64748b' }}>{t.description}</span>
                      </div>
                    </td>
                    <td>{t.pond_name || '-'}</td>
                    <td>
                      <div style={{ display: 'flex', flexDirection: 'column' }}>
                        <span>{t.assigned_to_name || 'Chưa giao'}</span>
                        {t.worker_usernames && <span style={{ fontSize: '0.75rem', color: '#94a3b8' }}>({t.worker_usernames})</span>}
                      </div>
                    </td>
                    <td>{formatDate(t.due_date)}</td>
                    <td>
                      <span className={getStatusClass(t.status)}>
                        {getStatusLabel(t.status)}
                      </span>
                    </td>
                    <td>
                      <div className="table-actions">
                        <button
                          type="button"
                          className="table-action-btn table-action-btn--view"
                          title="Xem chi tiết & Thao tác"
                          onClick={() => setSelectedTask(t)}
                        >
                          ⓘ Xem & Duyệt
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* PAGINATION */}
        <div className="table-pagination">
          <div className="table-pagination-left">
            <span>Số mục trên trang</span>
            <select
              value={pageSize}
              onChange={(e) => {
                setPageSize(Number(e.target.value) || 10)
                setCurrentPage(1)
              }}
            >
              {[5, 10, 20, 50].map((size) => (
                <option key={size} value={size}>{size}</option>
              ))}
            </select>
            <span>{filteredTasks.length === 0 ? 0 : startIndex + 1}-{endIndex} / {filteredTasks.length}</span>
          </div>

          <div className="table-pagination-right">
            <button
              type="button"
              className="btn btn-sm btn-secondary"
              disabled={safePage <= 1}
              onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
            >
              ‹
            </button>
            <span className="table-page-pill">{safePage}</span>
            <button
              type="button"
              className="btn btn-sm btn-secondary"
              disabled={safePage >= totalPages}
              onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
            >
              ›
            </button>
          </div>
        </div>
      </div>

      {/* DETAIL MODAL */}
      {selectedTask && (
        <div className="modal" onClick={() => setSelectedTask(null)}>
          <div className="modal-content admin-users_modal admin-users_modal--detail" onClick={(e) => e.stopPropagation()}>
            <h3>Chi tiết tiến độ công việc</h3>

            <div className="admin-users_detail-grid">
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Tiêu đề công việc</span>
                <strong>{selectedTask.task_title || '-'}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Ao nuôi áp dụng</span>
                <strong>{selectedTask.pond_name || '-'}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Thời gian bắt đầu</span>
                <strong>{formatDate(selectedTask.start_date)}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Thời hạn hoàn thành</span>
                <strong>{formatDate(selectedTask.due_date)}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Nhân công thực hiện</span>
                <strong>{selectedTask.assigned_to_name || '-'}</strong>
              </div>
              <div className="admin-users_detail-card">
                <span className="admin-users_detail-label">Trạng thái hiện tại</span>
                <span className={getStatusClass(selectedTask.status)} style={{ display: 'inline-block', marginTop: '4px' }}>
                  {getStatusLabel(selectedTask.status)}
                </span>
              </div>

              {selectedTask.product_name && (
                <div className="admin-users_detail-card" style={{ gridColumn: 'span 2', background: '#f0f9ff', border: '1px solid #bae6fd' }}>
                  <span className="admin-users_detail-label" style={{ color: '#0369a1' }}>Vật tư chỉ định đi kèm</span>
                  <strong>{selectedTask.product_name} — Số lượng: {selectedTask.quantity} {selectedTask.unit || ''}</strong>
                </div>
              )}

              <div className="admin-users_detail-card" style={{ gridColumn: 'span 2' }}>
                <span className="admin-users_detail-label">Hướng dẫn kỹ thuật</span>
                <p style={{ margin: '4px 0 0', color: '#334155', whiteSpace: 'pre-line' }}>{selectedTask.description || 'Không có hướng dẫn chi tiết.'}</p>
              </div>
            </div>

            {/* ĐIỀU KIỆN CHỈ CHO PHÉP ĐỔI TRẠNG THÁI KHI CHƯA HOÀN THÀNH HOẶC HỦY */}
            {['PENDING', 'IN_PROGRESS'].includes(normalize(selectedTask.status)) ? (
              <div style={{ marginTop: '20px' }}>
                <label className="admin-users_detail-label" style={{ marginBottom: '6px', display: 'block' }}>
                  Cập nhật trạng thái tiến độ:
                </label>
                <select
                  className="table-filter"
                  style={{ width: '100%', padding: '8px 12px' }}
                  value={selectedTask.status}
                  onChange={(e) => handleStatusChange(selectedTask.task_id, e.target.value)}
                >
                  <option value="PENDING">Chờ xử lý</option>
                  <option value="IN_PROGRESS">Đang thực hiện</option>
                  <option value="COMPLETED">Hoàn thành (Xuất kho & Hạch toán)</option>
                </select>
              </div>
            ) : (
              <div style={{ marginTop: '20px', padding: '10px', background: '#f8fafc', borderRadius: '6px', fontSize: '0.9rem', color: '#64748b', fontStyle: 'italic', textAlign: 'center' }}>
                Công việc này đã đóng. Không thể thay đổi thêm trạng thái.
              </div>
            )}

            <div className="admin-users_modal-buttons admin-users_form-buttons" style={{ marginTop: '24px', display: 'flex', justifyContent: 'space-between', width: '100%' }}>
              <div>
                {/* NÚT HỦY VIỆC: Chỉ hiện khi trạng thái là PENDING */}
                {normalize(selectedTask.status) === 'PENDING' && (
                  <button type="button" className="btn" style={{ backgroundColor: '#ef4444', color: '#fff' }} onClick={() => handleCancelTask(selectedTask.task_id)}>
                    Hủy bỏ công việc này
                  </button>
                )}
              </div>
              <div style={{ display: 'flex', gap: '8px' }}>
                <button type="button" className="btn btn-secondary" onClick={() => setSelectedTask(null)}>Đóng lại</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* CREATE TASK MODAL */}
      {isCreateOpen && (
        <div className="modal" onClick={() => setIsCreateOpen(false)}>
          <div className="modal-content admin-users_modal" style={{ maxWidth: '650px' }} onClick={(e) => e.stopPropagation()}>
            <h3>Phân công công việc mới</h3>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', marginTop: '16px' }}>

              {/* 1. LOẠI CÔNG VIỆC */}
              <div>
                <label className="admin-users_detail-label">Loại công việc kỹ thuật <span style={{ color: 'red' }}>*</span></label>
                <select
                  className="table-filter"
                  style={{ width: '100%', marginTop: '4px' }}
                  value={form.task_type}
                  onChange={handleTypeChange}
                >
                  <option value="">-- Chọn loại công việc --</option>
                  {TASK_TYPE_OPTIONS.map(opt => (
                    <option key={opt.value} value={opt.value}>{opt.label}</option>
                  ))}
                </select>
              </div>

              {/* 2. AO NUÔI (LỌC ĐỘNG THEO LOẠI VIỆC) */}
              <div>
                <label className="admin-users_detail-label">
                  Ao nuôi thực hiện <span style={{ color: 'red' }}>*</span> {loadingPonds && <span style={{ fontSize: '0.8rem', color: '#3b82f6' }}>(Đang lọc ao...)</span>}
                </label>
                <select
                  className="table-filter"
                  style={{ width: '100%', marginTop: '4px' }}
                  value={form.pond_id}
                  disabled={!form.task_type || loadingPonds}
                  onChange={handlePondChange}
                >
                  <option value="">
                    {form.task_type ? `-- Chọn ao nuôi (${ponds.length} ao phù hợp nghiệp vụ) --` : '-- Vui lòng chọn loại công việc trước --'}
                  </option>
                  {ponds.map((p) => (
                    <option key={p.pond_id} value={p.pond_id}>
                      {p.pond_name} ({normalize(p.status) === 'DANG_NUOI' ? 'Đang chạy vụ nuôi' : 'Đang cải tạo hạ tầng'})
                    </option>
                  ))}
                </select>
              </div>

              {/* 3. TIÊU ĐỀ CÔNG VIỆC TÙY CHỌN */}
              <div>
                <label className="admin-users_detail-label">Tiêu đề công việc (Để trống sẽ tự sinh theo loại việc)</label>
                <input
                  type="text"
                  placeholder="Ví dụ: Rải khoáng kích lột vỏ tôm cử chiều..."
                  style={{ width: '100%', marginTop: '4px', padding: '8px', borderRadius: '4px', border: '1px solid #cbd5e1' }}
                  value={form.task_title}
                  onChange={(e) => setForm({ ...form, task_title: e.target.value })}
                />
              </div>

              {/* 4. MÔ TẢ HƯỚNG DẪN KỸ THUẬT */}
              <div>
                <label className="admin-users_detail-label">Hướng dẫn kỹ thuật chi tiết <span style={{ color: 'red' }}>*</span></label>
                <textarea
                  placeholder="Nhập chi tiết liều lượng, vị trí rải thức ăn, cách thức hòa trộn sản phẩm hoặc ghi chú bắt buộc cho nhân công..."
                  style={{ width: '100%', marginTop: '4px', minHeight: '75px', padding: '8px', borderRadius: '4px', border: '1px solid #cbd5e1' }}
                  value={form.description}
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                />
              </div>

              {/* 5. VẬT TƯ / SẢN PHẨM HIỆN ĐỘNG */}
              {isProductRequired && (
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', background: '#f0f9ff', padding: '14px', borderRadius: '6px', border: '1px dashed #0284c7' }}>
                  <div>
                    <label className="admin-users_detail-label" style={{ color: '#0369a1' }}>Vật tư chỉ định sử dụng</label>
                    <select
                      className="table-filter"
                      style={{ width: '100%', marginTop: '4px', backgroundColor: '#fff' }}
                      value={form.product_id}
                      onChange={(e) => setForm({ ...form, product_id: e.target.value })}
                    >
                      <option value="">-- Chọn sản phẩm trong kho --</option>
                      {products.map((p) => (
                        <option key={p.product_id} value={p.product_id}>
                          {p.product_name}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="admin-users_detail-label" style={{ color: '#0369a1' }}>Số lượng định mức</label>
                    <input
                      type="number"
                      placeholder="Nhập khối lượng/số lượng..."
                      style={{ width: '100%', marginTop: '4px', padding: '6px 12px', borderRadius: '4px', border: '1px solid #cbd5e1', backgroundColor: '#fff' }}
                      value={form.quantity}
                      min="0"
                      step="0.01"
                      onChange={(e) => setForm({ ...form, quantity: e.target.value })}
                    />
                  </div>
                </div>
              )}

              {/* 6. LỊCH TRÌNH THỜI GIAN TRONG NGÀY */}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                <div>
                  <label className="admin-users_detail-label">Thời gian bắt đầu <span style={{ color: 'red' }}>*</span></label>
                  <input
                    type="datetime-local"
                    style={{ width: '100%', marginTop: '4px', padding: '8px', borderRadius: '4px', border: '1px solid #cbd5e1' }}
                    value={form.start_date}
                    onChange={(e) => setForm({ ...form, start_date: e.target.value })}
                  />
                </div>
                <div>
                  <label className="admin-users_detail-label">Hạn chót hoàn thành <span style={{ color: 'red' }}>*</span></label>
                  <input
                    type="datetime-local"
                    style={{ width: '100%', marginTop: '4px', padding: '8px', borderRadius: '4px', border: '1px solid #cbd5e1' }}
                    value={form.due_date}
                    onChange={(e) => setForm({ ...form, due_date: e.target.value })}
                  />
                </div>
              </div>

              {/* 7. DANH SÁCH CÔNG NHÂN (HIỂN THỊ TRẠNG THÁI BẬN CHUẨN BACKEND) */}
              <div>
                <label className="admin-users_detail-label" style={{ marginBottom: '6px', display: 'block' }}>
                  Giao việc cho nhân công phụ trách <span style={{ color: 'red' }}>*</span>
                </label>
                {workers.length === 0 ? (
                  <p style={{ fontStyle: 'italic', color: '#94a3b8', fontSize: '0.9rem' }}>Đang tải hoặc tổ của bạn hiện chưa có nhân công.</p>
                ) : (
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', maxHeight: '140px', overflowY: 'auto', padding: '8px', border: '1px solid #e2e8f0', borderRadius: '6px' }}>
                    {workers.map((w) => {
                      const isChecked = form.assigned_workers?.includes(w.user_id);
                      const isBusy = normalize(w.work_status) === 'BUSY';

                      return (
                        <div
                          key={w.user_id}
                          style={{
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'space-between',
                            padding: '6px',
                            borderRadius: '4px',
                            background: isBusy ? '#f1f5f9' : isChecked ? '#f0fdf4' : 'transparent',
                            border: isChecked && !isBusy ? '1px solid #bbf7d0' : '1px solid transparent',
                            opacity: isBusy ? 0.65 : 1,
                          }}
                        >
                          {/* Thay đổi từ <label> thành <label> lồng cấu trúc phẳng an toàn */}
                          <label
                            htmlFor={`worker-chk-${w.user_id}`} // Định danh rõ ràng kết nối click text -> ô input
                            style={{
                              display: 'flex',
                              alignItems: 'center',
                              gap: '8px',
                              cursor: isBusy ? 'not-allowed' : 'pointer',
                              width: '100%',
                              margin: 0
                            }}
                          >
                            <input
                              id={`worker-chk-${w.user_id}`}
                              type="checkbox"
                              checked={isChecked}
                              disabled={isBusy}
                              // CHỈ ĐẶT ONCHANGE TẠI ĐÂY, KHÔNG ĐẶT Ở THẺ CHA
                              onChange={() => toggleWorker(w.user_id, isBusy)}
                            />
                            <div style={{ display: 'flex', flexDirection: 'column' }}>
                              <strong style={{ fontSize: '0.9rem', color: isBusy ? '#94a3b8' : '#1e293b' }}>
                                {w.full_name}
                              </strong>
                              <span style={{ fontSize: '0.75rem', color: '#64748b' }}>@{w.username}</span>
                            </div>
                          </label>

                          <span style={{
                            fontSize: '0.7rem',
                            padding: '2px 6px',
                            borderRadius: '9999px',
                            fontWeight: '600',
                            backgroundColor: isBusy ? '#fee2e2' : '#dcfce7',
                            color: isBusy ? '#ef4444' : '#16a34a'
                          }}>
                            {isBusy ? 'Bận việc' : 'Sẵn sàng'}
                          </span>
                        </div>
                      )
                    })}
                  </div>
                )}
              </div>

            </div>

            {/* BUTTON ACTIONS */}
            <div className="admin-users_modal-buttons admin-users_form-buttons" style={{ marginTop: '24px' }}>
              <button type="button" className="btn btn-secondary" onClick={() => setIsCreateOpen(false)}>Hủy bỏ</button>
              <button
                type="button"
                className="btn btn-primary"
                onClick={handleCreateTask}
                disabled={!form.task_type || !form.pond_id || !form.start_date || !form.due_date}
              >
                Xác nhận phân công
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  )
}

export default TechnicianTasks
